final:
module bin2gray (
    input clk,
    input rst,
    input [3:0] bin,
    output [3:0] gray
);

reg [3:0] unused_gray_reg;

always @(posedge clk) begin
    if (rst) begin
        unused_gray_reg <= 4'b0;
    end else begin
        unused_gray_reg <= bin ^ (bin >> 1);
    end
end

assign gray = unused_gray_reg;

endmodule
